import json
import pandas as pd
import os

gl = globals()
# Load mapping variable (from earlier execute_python)
mapping_var = None
for k in list(gl.keys()):
    if k.startswith('var_call_') and '8sPApHfmPrpLxFoixe5XxPs2' in k:
        mapping_var = gl[k]
        mapping_key = k
        break
if mapping_var is None:
    # fallback: try to find any var_call that contains 'mapping' key when loaded
    mapping_var = None
    mapping_key = None

def load_maybe_json(v):
    if isinstance(v, str) and v.endswith('.json') and os.path.exists(v):
        with open(v, 'r') as f:
            return json.load(f)
    else:
        return v

mapping_data = None
if mapping_var is not None:
    mapping_data = load_maybe_json(mapping_var)
# if mapping_data is not as expected, try to find any var_call that loads to dict with 'mapping'
if not mapping_data or not isinstance(mapping_data, dict) or 'mapping' not in mapping_data:
    for k,v in gl.items():
        if k.startswith('var_call_'):
            try:
                candidate = load_maybe_json(v)
            except Exception:
                continue
            if isinstance(candidate, dict) and 'mapping' in candidate:
                mapping_data = candidate
                mapping_key = k
                break

# Gather symbol counts from all var_call_ variables
rows = []
for k,v in gl.items():
    if not k.startswith('var_call_'):
        continue
    # skip the mapping var
    if k == mapping_key:
        continue
    try:
        content = load_maybe_json(v)
    except Exception:
        continue
    # content might be a list like [{...}]
    if isinstance(content, list) and len(content) > 0 and isinstance(content[0], dict):
        rec = content[0]
        if 'symbol' in rec and 'cnt' in rec:
            try:
                cnt = int(rec['cnt'])
            except Exception:
                try:
                    cnt = int(float(rec['cnt']))
                except Exception:
                    continue
            rows.append((rec['symbol'], cnt))

# If no rows found, return empty
if not rows:
    result = []
else:
    df = pd.DataFrame(rows, columns=['symbol','cnt'])
    df = df.groupby('symbol', as_index=False).sum()
    df = df.sort_values('cnt', ascending=False)
    top5 = df.head(5)
    # Map to company descriptions using mapping_data
    names = []
    for sym in top5['symbol'].tolist():
        name = None
        if mapping_data and isinstance(mapping_data, dict):
            name = mapping_data.get('mapping', {}).get(sym)
        if not name:
            name = sym
        names.append(name)
    result = names

print('__RESULT__:')
print(json.dumps(result))

